from flask import Flask, jsonify
import pymemcache

app = Flask(__name__)

# Connect to Memcached at localhost:11211 using the pymemcache library
memcached_client = pymemcache.Client(["localhost:11211"])

@app.route("/api/v1/users", methods=["GET"])
def get_users():
    # Get users from database
    users = [{"id": 1, "name": "John Doe"}, {"id": 2, "name": "Jane Doe"}]

    # Cache the result for 60 seconds (TTL)
    memcached_client.set("users", jsonify(users), 60)

    return jsonify(users)

@app.route("/api/v1/users/<int:user_id>", methods=["GET"])
def get_user(user_id):
    # Get user from database
    user = {"id": user_id, "name": "John Doe"}

    # Cache the result for 60 seconds (TTL)
    memcached_client.set("user_{}".format(user_id), jsonify(user), 60)

    return jsonify(user)